1	import { statusColor } from "@/lib/utils/format";
2	
3	export function StatusBadge({ status }: { status: string }) {
4	  return (
5	    <span
6	      style={{
7	        display: "inline-block",
8	        padding: "2px 8px",
9	        borderRadius: "var(--radius-sm)",
10	        fontSize: "0.75rem",
11	        fontWeight: 600,
12	        textTransform: "uppercase",
13	        letterSpacing: "0.05em",
14	        color: statusColor(status),
15	        border: `1px solid ${statusColor(status)}`,
16	        background: "transparent",
17	      }}
18	    >
